
"use client"

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { LineChart, Mail, Lock, ArrowRight, ShieldCheck, Activity } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardHeader, CardTitle, CardContent, CardFooter, CardDescription } from '@/components/ui/card';
import { useAuth, useUser } from '@/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from 'firebase/auth';
import { toast } from '@/hooks/use-toast';

export default function LoginPage() {
  const router = useRouter();
  const auth = useAuth();
  const { user, isUserLoading } = useUser();
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [otpSent, setOtpSent] = useState(false);
  const [otp, setOtp] = useState('');

  useEffect(() => {
    if (user && !isUserLoading) {
      router.push('/dashboard');
    }
  }, [user, isUserLoading, router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (!otpSent) {
      // Logic for real email/password auth
      try {
        if (isLogin) {
          // Simulation of OTP requirement after credentials
          setOtpSent(true);
          toast({ title: "OTP Sent", description: "Verification code sent to your email." });
        } else {
          await createUserWithEmailAndPassword(auth, email, password);
          toast({ title: "Account Created", description: "Welcome to DeebData Trading!" });
        }
      } catch (error: any) {
        toast({ title: "Authentication Error", description: error.message, variant: "destructive" });
      } finally {
        setLoading(false);
      }
    } else {
      // Real code verification would happen here. For now, we simulate success with '123456'
      if (otp === '123456' || otp === '000000') {
        try {
          await signInWithEmailAndPassword(auth, email, password);
          router.push('/dashboard');
        } catch (error: any) {
          toast({ title: "Error", description: error.message, variant: "destructive" });
        }
      } else {
        toast({ title: "Invalid Code", description: "Please enter a valid 6-digit verification code.", variant: "destructive" });
      }
      setLoading(false);
    }
  };

  if (isUserLoading) return (
    <div className="min-h-screen bg-black flex items-center justify-center">
      <Activity className="h-8 w-8 text-primary animate-spin" />
    </div>
  );

  return (
    <div className="min-h-screen bg-black flex items-center justify-center p-4 relative overflow-hidden">
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-primary/10 rounded-full blur-[150px] pointer-events-none" />

      <Card className="w-full max-w-md border-white/10 glassmorphism relative z-10 overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-primary to-transparent opacity-50" />
        <CardHeader className="text-center pt-10">
          <div className="mx-auto w-16 h-16 bg-primary/10 border border-primary/30 rounded-2xl flex items-center justify-center mb-6 shadow-[0_0_20px_rgba(var(--primary),0.2)]">
            <LineChart className="h-8 w-8 text-primary" />
          </div>
          <CardTitle className="text-3xl font-black font-headline tracking-tighter mb-2 uppercase">
            {otpSent ? 'Verify Identity' : (isLogin ? 'Sign In' : 'Create Account')}
          </CardTitle>
          <CardDescription className="text-xs font-bold text-muted-foreground/60 uppercase tracking-widest">
            {otpSent 
              ? `Verification code sent to ${email}`
              : 'Institutional-grade technical signals'}
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-5">
            {!otpSent ? (
              <>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-muted-foreground uppercase tracking-wider ml-1">Email Address</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-3 h-4 w-4 text-muted-foreground/50" />
                    <Input 
                      type="email" 
                      placeholder="name@example.com" 
                      className="pl-10 bg-black/40 border-white/10 h-12 focus:border-primary/50 transition-all"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      required
                    />
                  </div>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-muted-foreground uppercase tracking-wider ml-1">Secure Password</label>
                  <div className="relative">
                    <Lock className="absolute left-3 top-3 h-4 w-4 text-muted-foreground/50" />
                    <Input 
                      type="password" 
                      placeholder="••••••••" 
                      className="pl-10 bg-black/40 border-white/10 h-12 focus:border-primary/50 transition-all"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                    />
                  </div>
                </div>
              </>
            ) : (
              <div className="space-y-3">
                <label className="text-[10px] font-black text-center block text-primary uppercase tracking-[0.2em]">6-Digit Security Code</label>
                <div className="relative">
                  <ShieldCheck className="absolute left-3 top-3 h-4 w-4 text-primary/50" />
                  <Input 
                    placeholder="000000" 
                    className="pl-10 bg-black/40 border-white/20 h-14 text-center tracking-[1em] font-black text-2xl text-primary"
                    maxLength={6}
                    value={otp}
                    onChange={(e) => setOtp(e.target.value)}
                    required
                    autoFocus
                  />
                </div>
                <p className="text-[10px] text-center text-muted-foreground">Test Code: <span className="text-primary font-bold">123456</span></p>
              </div>
            )}
            <Button type="submit" className="w-full bg-primary text-black font-black h-14 text-lg hover:shadow-[0_0_20px_rgba(var(--primary),0.4)] transition-all" disabled={loading}>
              {loading ? <Activity className="h-5 w-5 animate-spin" /> : (otpSent ? 'Confirm & Access' : (isLogin ? 'Sign In Now' : 'Join Platform'))}
              {!loading && <ArrowRight className="ml-2 h-5 w-5" />}
            </Button>
          </form>
        </CardContent>
        <CardFooter className="flex flex-col space-y-6 pb-10">
          <div className="text-center text-xs">
            {otpSent ? (
              <button onClick={() => setOtpSent(false)} className="text-primary font-bold hover:underline">
                Incorrect email? Go back
              </button>
            ) : (
              <span className="text-muted-foreground font-medium">
                {isLogin ? "New to DeebData? " : "Already registered? "}
                <button 
                  onClick={() => setIsLogin(!isLogin)} 
                  className="text-primary font-black hover:underline uppercase tracking-tighter"
                >
                  {isLogin ? 'Create Profile' : 'Access Account'}
                </button>
              </span>
            )}
          </div>
          <div className="text-[10px] text-center text-muted-foreground/30 font-bold uppercase tracking-[0.3em]">
            Powered by Hassan Deeb
          </div>
        </CardFooter>
      </Card>
    </div>
  );
}
